struct hash<web_api::QueryResult>
{
    typedef web_api::QueryResult argument_type;
    typedef size_t result_type;

    result_type operator () (const argument_type& value) const
    {
        result_type result = 17;
        result = result * 31 + std::hash<decltype(value.query_id)>()(value.query_id);
        return result;
    }
};

